VALUES
  ('male_sexual_health', 1, 'Reset & Activation', 'Phase 1: Foundation & Activation', 'Start your recovery by reducing stimulation, activating your body, and building awareness.', '{"day_number":1,"day_title":"Reset & Activation","day_goal":"Start your recovery by reducing stimulation, activating your body, and building awareness.","estimated_minutes":12,"lesson_highlight":"Progress comes from consistency, not intensity alone.","morning_reset_instructions":["Avoid porn today.","When the urge appears, use CALM, delay 5–10 minutes, and shift focus.","Drink 1–2 glasses of water after waking.","Optional: add soaked almonds or raisins."],"morning_reset_why":"Reducing stimulation and giving the body an early reset builds control and steadier recovery momentum.","breathing_title":"Breathing Exercise (2 minutes)","breathing_instructions":"• Sit comfortably and relax your body • Inhale through your nose → 4 seconds • Exhale slowly → 6 seconds Repeat for 2 minutes • reduces stress and anxiety • improves focus and control • calms the nervous system","routine_exercises":[{"name":"Pelvic Strength — Hold & Release","instructions":["• Tighten the pelvic muscle fully","• Hold for 6 seconds","• Release completely for 3 seconds","16 reps × 1 sets Rest 15 seconds between sets"]},{"name":"Pelvic Activation — Pillow Squeeze Kegels","instructions":["• Lie on your back with knees bent","• Place a pillow between your thighs","• Gently squeeze the pillow","12–15 reps × 1 sets Hold 5–7 seconds Rest 15 seconds between sets"]},{"name":"Hip & Glute Strength — Glute Bridge March","instructions":["• Lie on your back with knees bent","• Lift hips into a glute bridge position","• While holding the bridge, lift one foot slightly","22 alternating marches × 1 sets Rest 20 seconds between sets"]},{"name":"Circulation Boost — Brisk Walk","instructions":["• Walk at a steady pace","• Keep breathing natural","• Maintain consistent movement","15–20 minutes","• improves blood circulation"]}],"night_routine_instructions":["Avoid phone 30 minutes before bed.","Do slow breathing and relax your body.","Wear loose pants while sleeping."],"night_routine_why":"improves blood circulation reduces pressure in pelvic area supports natural recovery"}'::jsonb, '{}'::jsonb),
